const ctx = $json.context_json ?? {};

ctx.flow = 'events';
ctx.step = 'awaiting_event_contact_name';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};

const reply = `Sí, atendemos eventos con experiencia wok en vivo 🍜

Incluimos normalmente:
- Maestros wokeros
- Cocinas boca de dragón y woks
- Mesas de trabajo
- Equipos y utensilios
- Envases y cubiertos descartables ecológicos

Como referencia:
- Chaufa Clásico desde S/ 13.90 por persona
- Chaufa Aeropuerto desde S/ 15.90 por persona
- Wantix como complemento desde S/ 2.40 por unidad

El transporte se cotiza aparte.

Si deseas, puedo registrar tu solicitud para que el equipo comercial te contacte. ¿A nombre de quién registramos la solicitud?`;

return [
  {
    json: {
      ...$json,
      reply_text: reply,
      new_flow: 'events',
      new_step: 'awaiting_event_contact_name',
      context_json: ctx
    }
  }
];

const text = ($json.message_text || '').trim();
const ctx = $json.context_json ?? {};

if (!text || text.length < 2) {
  return [{
    json: {
      ...$json,
      reply_text: 'Por favor indícame el nombre del contacto para registrar la solicitud.',
      new_flow: 'events',
      new_step: 'awaiting_event_contact_name',
      context_json: ctx
    }
  }];
}

ctx.flow = 'events';
ctx.step = 'awaiting_event_phone';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.contact_name = text;

return [{
  json: {
    ...$json,
    reply_text: `Gracias, ${text}. ¿Cuál es tu número de contacto?`,
    new_flow: 'events',
    new_step: 'awaiting_event_phone',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const digits = text.replace(/\D/g, '');
const ctx = $json.context_json ?? {};

if (!/^\d{9}$/.test(digits)) {
  return [{
    json: {
      ...$json,
      reply_text: 'Por favor indícame un número válido de 9 dígitos.',
      new_flow: 'events',
      new_step: 'awaiting_event_phone',
      context_json: ctx
    }
  }];
}

ctx.flow = 'events';
ctx.step = 'awaiting_event_guest_count';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.phone = digits;

return [{
  json: {
    ...$json,
    reply_text: 'Perfecto. ¿Para cuántas personas sería el evento?',
    new_flow: 'events',
    new_step: 'awaiting_event_guest_count',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const qty = parseInt(text.replace(/\D/g, ''), 10);
const ctx = $json.context_json ?? {};

if (!Number.isInteger(qty) || qty <= 0) {
  return [{
    json: {
      ...$json,
      reply_text: 'Por favor indícame una cantidad válida de asistentes.',
      new_flow: 'events',
      new_step: 'awaiting_event_guest_count',
      context_json: ctx
    }
  }];
}

ctx.flow = 'events';
ctx.step = 'awaiting_event_date';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.attendee_count = qty;

return [{
  json: {
    ...$json,
    reply_text: 'Gracias. ¿Cuál es la fecha del evento?',
    new_flow: 'events',
    new_step: 'awaiting_event_date',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const ctx = $json.context_json ?? {};

function normalizeDate(input) {
  const value = input.trim();

  // YYYY-MM-DD
  let m = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m) {
    const [, y, mo, d] = m;
    const iso = `${y}-${mo}-${d}`;
    const dt = new Date(`${iso}T00:00:00`);
    if (!isNaN(dt.getTime()) && dt.getUTCFullYear() === Number(y) && dt.getUTCMonth() + 1 === Number(mo) && dt.getUTCDate() === Number(d)) {
      return iso;
    }
  }

  // DD/MM/YYYY o DD-MM-YYYY
  m = value.match(/^(\d{2})[\/-](\d{2})[\/-](\d{4})$/);
  if (m) {
    const [, d, mo, y] = m;
    const iso = `${y}-${mo}-${d}`;
    const dt = new Date(`${iso}T00:00:00`);
    if (!isNaN(dt.getTime()) && dt.getUTCFullYear() === Number(y) && dt.getUTCMonth() + 1 === Number(mo) && dt.getUTCDate() === Number(d)) {
      return iso;
    }
  }

  return null;
}

const normalizedDate = normalizeDate(text);

if (!normalizedDate) {
  return [{
    json: {
      ...$json,
      reply_text: 'Por favor indícame la fecha del evento en formato válido. Ejemplo: 2026-04-22 o 22/04/2026.',
      new_flow: 'events',
      new_step: 'awaiting_event_date',
      context_json: ctx
    }
  }];
}

ctx.flow = 'events';
ctx.step = 'awaiting_event_location';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.event_date = normalizedDate;
ctx.event_request.event_date_raw = text;

return [{
  json: {
    ...$json,
    reply_text: 'Perfecto. ¿Dónde se realizará el evento?',
    new_flow: 'events',
    new_step: 'awaiting_event_location',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const ctx = $json.context_json ?? {};

if (!text || text.length < 4) {
  return [{
    json: {
      ...$json,
      reply_text: 'Por favor indícame la ubicación del evento.',
      new_flow: 'events',
      new_step: 'awaiting_event_location',
      context_json: ctx
    }
  }];
}

ctx.flow = 'events';
ctx.step = 'awaiting_event_chaufa_choice';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.location_text = text;

return [{
  json: {
    ...$json,
    reply_text: 'Gracias. ¿Qué opción te interesa más para el evento: Chaufa Clásico, Chaufa Aeropuerto o aún no lo tienes definido?',
    new_flow: 'events',
    new_step: 'awaiting_event_chaufa_choice',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const lower = text.toLowerCase();
const ctx = $json.context_json ?? {};

let choice = 'por_definir';
if (lower.includes('clasico') || lower.includes('clásico')) choice = 'chaufa_clasico';
if (lower.includes('aeropuerto')) choice = 'chaufa_aeropuerto';

ctx.flow = 'events';
ctx.step = 'awaiting_event_notes';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.selected_chaufa = choice;
ctx.event_request.selected_chaufa_text = text;

return [{
  json: {
    ...$json,
    reply_text: 'Perfecto. ¿Deseas agregar alguna observación adicional? Por ejemplo horario, complemento como wantix, tipo de evento o algún requerimiento especial. Si no, puedes responder "no".',
    new_flow: 'events',
    new_step: 'awaiting_event_notes',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim();
const ctx = $json.context_json ?? {};

ctx.flow = 'events';
ctx.step = 'awaiting_event_confirmation';
ctx.intent = 'event_lead';
ctx.event_request = ctx.event_request || {};
ctx.event_request.notes = /^no$/i.test(text) ? null : text;

const er = ctx.event_request || {};

const reply = `Perfecto, este es el resumen de tu solicitud:

Nombre: ${er.contact_name || '-'}
Teléfono: ${er.phone || '-'}
Asistentes: ${er.attendee_count || '-'}
Fecha: ${er.event_date || '-'}
Ubicación: ${er.location_text || '-'}
Opción de chaufa: ${er.selected_chaufa_text || 'Por definir'}
Observaciones: ${er.notes || '-'}

¿Deseas confirmar el registro de esta solicitud? Puedes responder: sí o no.`;

return [{
  json: {
    ...$json,
    reply_text: reply,
    new_flow: 'events',
    new_step: 'awaiting_event_confirmation',
    context_json: ctx
  }
}];

const text = ($json.message_text || '').trim().toLowerCase();
const ctx = $json.context_json ?? {};

const yesWords = ['si', 'sí', 'ok', 'confirmar', 'confirmo', 'dale'];
const noWords = ['no', 'cancelar', 'aun no', 'aún no'];

if (yesWords.some(w => text.includes(w))) {
  ctx.flow = 'events';
  ctx.step = 'event_lead_registered';
  ctx.intent = 'event_lead';

  return [{
    json: {
      ...$json,
      event_confirmation_result: 'confirmed',
      reply_text: '¡Perfecto! Tu solicitud fue registrada. El equipo comercial de Guaw te contactará para continuar con la propuesta y disponibilidad.',
      new_flow: 'events',
      new_step: 'event_lead_registered',
      context_json: ctx
    }
  }];
}

if (noWords.some(w => text.includes(w))) {
  ctx.flow = 'events';
  ctx.step = 'awaiting_event_contact_name';
  ctx.intent = 'event_lead';

  return [{
    json: {
      ...$json,
      event_confirmation_result: 'rejected',
      reply_text: 'Entendido. Si deseas, puedo volver a registrar la solicitud desde cero. ¿A nombre de quién la registramos?',
      new_flow: 'events',
      new_step: 'awaiting_event_contact_name',
      context_json: ctx
    }
  }];
}

return [{
  json: {
    ...$json,
    event_confirmation_result: 'unknown',
    reply_text: 'Por favor respóndeme si deseas confirmar la solicitud con un "sí" o "no".',
    new_flow: 'events',
    new_step: 'awaiting_event_confirmation',
    context_json: ctx
  }
}];

const raw = $json.output ?? $json.text ?? '';

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    kind: 'unclear',
    target_step: null,
    normalized_value: null,
    answer_to_user: 'No logré interpretar tu respuesta. ¿Podrías intentarlo nuevamente?',
    reason: 'No se pudo parsear la respuesta del guard.'
  };
}

return [{ json: parsed }];

const original = $('When Executed by Another Workflow').first().json;
const guard = $json;
const ctx = original.context_json ?? {};

return [
  {
    json: {
      ...original,
      reply_text: guard.answer_to_user || 'Claro, te ayudo con esa duda. Luego continuamos con el dato pendiente.',
      new_flow: original.current_flow,
      new_step: original.current_step,
      context_json: ctx
    }
  }
];

const original = $('When Executed by Another Workflow').first().json;
const guard = $('Parse Guard JSON').first().json;

const ctx = original.context_json ?? {};
ctx.event_request = ctx.event_request || {};
ctx.flow = 'events';
ctx.intent = 'event_lead';

const step = guard.target_step || original.current_step;
const value = guard.normalized_value;

let reply_text = '';
let new_step = step;

switch (step) {
  case 'awaiting_event_contact_name':
    ctx.event_request.contact_name = value;
    new_step = 'awaiting_event_phone';
    reply_text = `Gracias, ${value}. ¿Cuál es tu número de contacto?`;
    break;

  case 'awaiting_event_phone':
    ctx.event_request.phone = value;
    new_step = 'awaiting_event_guest_count';
    reply_text = 'Perfecto. ¿Para cuántas personas sería el evento?';
    break;

  case 'awaiting_event_guest_count':
    ctx.event_request.attendee_count = Number(value);
    new_step = 'awaiting_event_date';
    reply_text = 'Gracias. ¿Cuál es la fecha del evento? Puedes escribirla como 2026-04-22 o 22/04/2026.';
    break;

  case 'awaiting_event_date':
    ctx.event_request.event_date = value;
    ctx.event_request.event_date_raw = original.message_text;
    new_step = 'awaiting_event_location';
    reply_text = 'Perfecto. ¿Dónde se realizará el evento?';
    break;

  case 'awaiting_event_location':
    ctx.event_request.location_text = value;
    new_step = 'awaiting_event_chaufa_choice';
    reply_text = 'Gracias. ¿Qué opción te interesa más para el evento: Chaufa Clásico, Chaufa Aeropuerto o aún no lo tienes definido?';
    break;

  case 'awaiting_event_chaufa_choice':
    ctx.event_request.selected_chaufa = value;
    ctx.event_request.selected_chaufa_text = original.message_text;
    new_step = 'awaiting_event_notes';
    reply_text = 'Perfecto. ¿Deseas agregar alguna observación adicional? Por ejemplo horario, complemento como wantix, tipo de evento o algún requerimiento especial. Si no, puedes responder "no".';
    break;

  case 'awaiting_event_notes':
    ctx.event_request.notes = String(value || '').toLowerCase() === 'no' ? null : value;
    new_step = 'awaiting_event_confirmation';

    const er = ctx.event_request || {};
    reply_text = `Perfecto, este es el resumen de tu solicitud:

Nombre: ${er.contact_name || '-'}
Teléfono: ${er.phone || '-'}
Asistentes: ${er.attendee_count || '-'}
Fecha: ${er.event_date || '-'}
Ubicación: ${er.location_text || '-'}
Opción de chaufa: ${er.selected_chaufa_text || 'Por definir'}
Observaciones: ${er.notes || '-'}

¿Deseas confirmar el registro de esta solicitud? Puedes responder: sí o no.`;
    break;

  default:
    reply_text = 'Continuemos con tu solicitud.';
    new_step = step;
    break;
}

ctx.step = new_step;

return [{
  json: {
    ...original,
    reply_text,
    new_flow: 'events',
    new_step,
    context_json: ctx
  }
}];

const original = $('When Executed by Another Workflow').first().json;
const guard = $('Parse Guard JSON - Events').first().json;
const ctx = original.context_json ?? {};

return [{
  json: {
    ...original,
    reply_text: guard.answer_to_user || 'No logré identificar bien tu respuesta. ¿Podrías intentarlo nuevamente?',
    new_flow: 'events',
    new_step: original.current_step,
    context_json: ctx
  }
}];

const original = $('When Executed by Another Workflow').first().json;
const guard = $('Parse Guard JSON').first().json;
const ctx = original.context_json ?? {};

return [{
  json: {
    ...original,
    reply_text: guard.answer_to_user || 'Claro. Si deseas cambiar de tema, también puedo ayudarte con delivery o con más información del servicio.',
    new_flow: 'events',
    new_step: original.current_step,
    context_json: ctx
  }
}];

const original = $('When Executed by Another Workflow').first().json;
const text = (original.message_text || '').trim().toLowerCase();
const ctx = original.context_json ?? {};
const currentStep = original.current_step || 'awaiting_more_items';

function reprompt(step) {
  switch (step) {
    case 'awaiting_more_items':
      return '¿Deseas agregar algo más a tu pedido? Puedes responder por ejemplo: "sí" o "no, eso es todo".';
    case 'awaiting_product_selection':
      return '¿Cuál deseas pedir?';
    case 'awaiting_customer_name':
      return '¿A nombre de quién registramos el pedido?';
    case 'awaiting_customer_phone':
      return '¿Cuál es tu número de celular para coordinar el delivery?';
    case 'awaiting_address':
      return 'Ahora compárteme la dirección de delivery.';
    case 'awaiting_order_confirmation':
      return '¿Deseas confirmar tu pedido? Puedes responder: sí o no.';
    default:
      return 'Continuemos con tu pedido.';
  }
}

let faqKey = null;
let faqAnswer = null;

// Taypá
if (text.includes('taypa') || text.includes('taypá') || text.includes('armalo taypa') || text.includes('ármalo taypá')) {
  faqKey = 'taypa_info';
  faqAnswer = 'Ármalo Taypá es una opción configurable desde S/ 26.90. Puedes elegir una proteína, hasta 4 verduras o frutas y una salsa. También puedes agregar extras adicionales.';
}

// Preguntas sobre delivery
else if (text.includes('delivery') || text.includes('costo de delivery') || text.includes('cuanto cuesta el delivery') || text.includes('cuánto cuesta el delivery')) {
  faqKey = 'delivery_info';
  faqAnswer = 'El costo de delivery se calcula según la zona o distrito y, para la demo, si no se identifica la zona se aplica una tarifa referencial.';
}

// Preguntas sobre tiempo
else if (text.includes('cuanto demora') || text.includes('cuánto demora') || text.includes('tiempo de entrega') || text.includes('cuanto tarda') || text.includes('cuánto tarda')) {
  faqKey = 'eta_info';
  faqAnswer = 'El tiempo estimado de entrega depende de la zona. Para la demo normalmente manejamos una referencia de 45 a 60 minutos.';
}

return [{
  json: {
    ...original,
    faq_matched: !!faqKey,
    faq_key: faqKey,
    faq_answer: faqAnswer,
    reprompt_text: reprompt(currentStep),
    new_flow: original.current_flow,
    new_step: currentStep,
    context_json: ctx
  }
}];
